// Populate the homepage "by the numbers" from the shipped datasets so they stay
// in sync with the repo automatically — no hand-editing index.md on every
// curated-data refresh. The HTML keeps sensible fallback values for no-JS /
// pre-fetch; this script overwrites them once the JSON loads.
//
// Sources (regenerated by `make docs-data`):
//   malicious-packages.json -> curated-entry count + distinct ecosystems
//   skills.json             -> skills count
//   stats.json              -> cve / secret / assistant-integration counts
//
// Mirrors the client-side rendering already used by Coverage / Threat-Intel.
// Hooks Material's `document$` so it survives instant navigation.
document$.subscribe(function () {
  var sel = "[data-sv-stat],[data-sv-card]";
  if (!document.querySelector(sel)) return; // not the homepage

  function dataURL(p) { return new URL(p, document.baseURI).href; }
  function getJSON(p) { return fetch(dataURL(p)).then(function (r) { return r.json(); }); }
  function setStat(key, value) {
    var el = document.querySelector('[data-sv-stat="' + key + '"]');
    if (el && value != null) el.textContent = String(value);
  }
  function setCard(key, text) {
    var el = document.querySelector('[data-sv-card="' + key + '"]');
    if (el && text) el.textContent = text;
  }

  getJSON("assets/data/malicious-packages.json").then(function (d) {
    var entries = d.entries || [];
    var total = typeof d.count === "number" ? d.count : entries.length;
    var ecos = {};
    entries.forEach(function (e) { if (e.ecosystem) ecos[e.ecosystem] = 1; });
    var nEcos = Object.keys(ecos).length;
    var totalStr = total.toLocaleString("en-US");
    setStat("malicious", totalStr);
    setStat("ecosystems", nEcos);
    setCard(
      "supply",
      totalStr + " web-cited malicious-package entries across " + nEcos +
        " ecosystems + typosquats. Browse the curated canon →"
    );
  }).catch(function () { /* keep static fallback */ });

  getJSON("assets/data/skills.json").then(function (d) {
    setStat("skills", (d.skills && d.skills.length) || d.count);
  }).catch(function () { /* keep static fallback */ });

  getJSON("assets/data/stats.json").then(function (d) {
    setStat("cve", d.cve_patterns);
    setStat("secret", d.secret_patterns);
    setStat("integrations", d.assistant_integrations);
    if (d.secret_patterns != null) {
      setCard(
        "secrets",
        d.secret_patterns + " secret-detection patterns optimised for " +
          "AI-assistant context, with entropy and hotword-proximity scoring."
      );
    }
  }).catch(function () { /* keep static fallback */ });
});
